Rule.Source:
  import sailpoint.object.Custom;
  import sailpoint.object.Link;
  import sailpoint.object.identity;
  import sailpoint.api.IdentityService;

  //variable declaration for immediate termination
  String previousIdentityManualTerm = previousIdentity!=null?previousIdentity.getStringAttribute("manualTerm"):null;
  String newIdentityManualTerm = newIdentity!=null? newIdentity.getStringAttribute("manualTerm"):null;
  boolean isNewIdentityInactive = newIdentity!=null? newIdentity.isInactive():false;
  String DB_Peoplesoft_HCM_Primary = "DB-Peoplesoft-HCM-Primary";
  String MDStaff_AMITA="MDStaff - AMITA";
  
  List actionCodes = null;


  String hrAppAccount=null;

  Custom customRehireConfig = context.getObjectByName(Custom.class,"Ascension-Custom-Rehire-Configuration");
  if(null != customRehireConfig){
    actionCodes = customRehireConfig.get("RehireActionCode");
  }

  String logName = "Ascension-Rule-IdentityTrigger-Rehire";

  debug(logName, "Entering Rule Ascension-Rule-IdentityTrigger-Rehire");
  
  boolean triggerRehire = false;
  if(previousIdentity != null && previousIdentity.isInactive() == true && newIdentity != null && newIdentity.isInactive() == false)
  {    
    String identityType = newIdentity.getStringAttribute("type");
    Custom custom = context.getObjectByName(Custom.class, "Ascension-Custom-ContractorConfiguration");
    List validUserTypes = custom.get("userTypes");
    if(null != validUserTypes && validUserTypes.contains(identityType)){
      debug(logName, "Rehire event is triggered for the identity: " + newIdentity.getName());
      triggerRehire = true;
    }
  } else if((null != previousIdentity) && (null != newIdentity) && ("Yes".equalsIgnoreCase(previousIdentityManualTerm)) && ("Yes".equalsIgnoreCase(newIdentityManualTerm)) && isNewIdentityInactive == true)
  { 
    //code for rehire trigger on immediate termination

    Map oldIdentityMap = getAttributeMap(previousIdentity);
    Map newIdentityMap = getAttributeMap(newIdentity);
    if(MDStaff_AMITA.equalsIgnoreCase(oldIdentityMap.get("hrAppAccount")) && oldIdentityMap.get("linkStatus") == true && newIdentityMap.get("linkStatus") == false)
    {
      debug(logName, "Manual Term Case - Rehire event is triggered for the identity: " + newIdentity.getName());
      triggerRehire = true;
    }
    else if((DB_Peoplesoft_HCM_Primary.equalsIgnoreCase(oldIdentityMap.get("hrAppAccount"))) && (oldIdentityMap.get("action") != newIdentityMap.get("action")) && (actionCodes.contains(newIdentityMap.get("action"))) && oldIdentityMap.get("linkStatus") == true && newIdentityMap.get("linkStatus") == false)
    {
      debug(logName, "Manual Term Case - Rehire event is triggered for the identity: " + newIdentity.getName());
      triggerRehire = true;
    }
  }
  debug(logName, "Exiting Rule Ascension-Rule-IdentityTrigger-Rehire");
  return triggerRehire;
